import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import MovieCard from '../components/movies/MovieCard';
import LoadingSpinner from '../components/common/LoadingSpinner';
import { getMovies, getGenres, searchMovies } from '../services/movieService';
import './MoviesPage.css';

const MoviesPage = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [movies, setMovies] = useState([]);
  const [genres, setGenres] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchQuery, setSearchQuery] = useState(searchParams.get('q') || '');
  const [selectedGenre, setSelectedGenre] = useState(searchParams.get('genre') || '');
  const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'avg_rating');
  const [page, setPage] = useState(1);
  const [hasMore, setHasMore] = useState(true);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    fetchGenres();
  }, []);

  useEffect(() => {
    fetchMovies(true); // true means reset the movies list
  }, [selectedGenre, sortBy, searchQuery]);

  const fetchGenres = async () => {
    try {
      const data = await getGenres();
      setGenres(data.genres);
    } catch (error) {
      console.error('Error fetching genres:', error);
    }
  };

  const fetchMovies = async (reset = false) => {
    if (!reset && !hasMore) return;

    setLoading(true);
    setError(null);

    try {
      let data;
      const currentPage = reset ? 1 : page;

      if (searchQuery.trim()) {
        data = await searchMovies(searchQuery, 20);
        setHasMore(false); // Search doesn't support pagination yet
      } else {
        data = await getMovies({
          page: currentPage,
          limit: 20,
          genre: selectedGenre,
          sort_by: sortBy
        });
        setHasMore(data.movies.length === 20);
      }

      if (reset) {
        setMovies(data.movies);
        setPage(2);
      } else {
        setMovies(prev => [...prev, ...data.movies]);
        setPage(prev => prev + 1);
      }
    } catch (error) {
      console.error('Error fetching movies:', error);
      setError('Failed to load movies. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = async (e) => {
    e.preventDefault();
    if (searchQuery.trim() === searchParams.get('q')) return;

    setIsSearching(true);
    updateURLParams({ q: searchQuery.trim(), genre: '', page: 1 });
    setSelectedGenre('');
    await fetchMovies(true);
    setIsSearching(false);
  };

  const handleGenreChange = (genre) => {
    if (genre === selectedGenre) return;

    setSelectedGenre(genre);
    setSearchQuery('');
    updateURLParams({ genre, q: '', page: 1 });
  };

  const handleSortChange = (sort) => {
    if (sort === sortBy) return;

    setSortBy(sort);
    updateURLParams({ sort });
  };

  const updateURLParams = (params) => {
    const newParams = new URLSearchParams(searchParams);

    Object.entries(params).forEach(([key, value]) => {
      if (value) {
        newParams.set(key, value);
      } else {
        newParams.delete(key);
      }
    });

    setSearchParams(newParams);
  };

  const clearFilters = () => {
    setSearchQuery('');
    setSelectedGenre('');
    setSortBy('avg_rating');
    setSearchParams({});
  };

  const loadMore = () => {
    fetchMovies(false);
  };

  if (loading && movies.length === 0) {
    return <LoadingSpinner />;
  }

  return (
    <div className="movies-page">
      <div className="movies-header">
        <h1>🎬 Browse Movies</h1>
        <p>Discover your next favorite movie</p>
      </div>

      {/* Search and Filters */}
      <div className="movies-filters">
        <form onSubmit={handleSearch} className="search-form">
          <div className="search-input-group">
            <input
              type="text"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder="Search movies by title..."
              className="search-input"
            />
            <button 
              type="submit" 
              className="search-button"
              disabled={isSearching}
            >
              {isSearching ? '🔄' : '🔍'}
            </button>
          </div>
        </form>

        <div className="filter-row">
          <div className="genre-filter">
            <label>Genre:</label>
            <select
              value={selectedGenre}
              onChange={(e) => handleGenreChange(e.target.value)}
              className="filter-select"
            >
              <option value="">All Genres</option>
              {genres.map(genre => (
                <option key={genre.name} value={genre.name}>
                  {genre.name}
                </option>
              ))}
            </select>
          </div>

          <div className="sort-filter">
            <label>Sort by:</label>
            <select
              value={sortBy}
              onChange={(e) => handleSortChange(e.target.value)}
              className="filter-select"
            >
              <option value="avg_rating">Rating</option>
              <option value="year">Year</option>
              <option value="title">Title</option>
            </select>
          </div>

          {(selectedGenre || searchQuery || sortBy !== 'avg_rating') && (
            <button onClick={clearFilters} className="clear-filters">
              Clear Filters
            </button>
          )}
        </div>
      </div>

      {/* Active Filters Display */}
      {(selectedGenre || searchQuery) && (
        <div className="active-filters">
          <span className="filters-label">Active filters:</span>
          {searchQuery && (
            <span className="filter-tag">
              Search: "{searchQuery}"
              <button onClick={() => {
                setSearchQuery('');
                updateURLParams({ q: '' });
              }}>×</button>
            </span>
          )}
          {selectedGenre && (
            <span className="filter-tag">
              Genre: {selectedGenre}
              <button onClick={() => handleGenreChange('')}>×</button>
            </span>
          )}
        </div>
      )}

      {/* Error Message */}
      {error && (
        <div className="error-message">
          {error}
          <button onClick={() => fetchMovies(true)}>Try Again</button>
        </div>
      )}

      {/* Movies Grid */}
      {movies.length > 0 ? (
        <>
          <div className="movies-grid">
            {movies.map(movie => (
              <MovieCard key={movie.id} movie={movie} />
            ))}
          </div>

          {/* Load More Button */}
          {hasMore && !searchQuery && (
            <div className="load-more-section">
              <button
                onClick={loadMore}
                disabled={loading}
                className="load-more-button"
              >
                {loading ? 'Loading...' : 'Load More Movies'}
              </button>
            </div>
          )}
        </>
      ) : !loading && (
        <div className="no-movies">
          <h3>No movies found</h3>
          <p>
            {searchQuery 
              ? `No movies match your search for "${searchQuery}"`
              : selectedGenre 
                ? `No ${selectedGenre} movies found`
                : 'No movies available'
            }
          </p>
          {(searchQuery || selectedGenre) && (
            <button onClick={clearFilters} className="clear-filters">
              Clear Filters
            </button>
          )}
        </div>
      )}

      {/* Results Summary */}
      {movies.length > 0 && (
        <div className="results-summary">
          Showing {movies.length} movies
          {searchQuery && ` for "${searchQuery}"`}
          {selectedGenre && ` in ${selectedGenre}`}
        </div>
      )}
    </div>
  );
};

export default MoviesPage;
